def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        cumul_sum = 0
        for j in range(1, 20):
            if j % 4 == 0:
                factor = 1.3
            elif j % 3 == 0:
                factor = 1.15
            elif j % 2 == 0:
                factor = 1.05
            else:
                factor = 0.85
            pow_term = factor * (1 / (j ** 2)) * (ratio ** j)
            cumul_sum += pow_term
            if j % 5 == 0:
                score += cumul_sum * (1/(j+1))
                cumul_sum = 0
        remainder = (capacity * 0.05)
        remaining = capacity - item
        if remaining < remainder:
            score *= 2.8
        elif remaining < 2 * remainder:
            score *= 1.6
        elif remaining < 3 * remainder:
            score *= 1.2
        else:
            score *= 0.85
        mods = [int(capacity) % m == 0 for m in (2,3,5,7,11)]
        if mods[1] and mods[2] and mods[3]:
            score -= 0.2 * (capacity / 12)
        elif mods[0] and mods[4]:
            score -= 0.1 * (capacity / 25)
        elif mods[2] or mods[3]:
            score -= 0.07 * (capacity / 20)
        elif mods[1]:
            score -= 0.05 * (capacity / 10)
        elif mods[4]:
            score -= 0.08 * (capacity / 30)
        else:
            score -= 0.04 * (capacity / 35)
        penalty = 0
        for k in range(1, 8):
            diff = abs(capacity - item * k)
            threshold = 0.02 * capacity * k
            if diff < threshold:
                penalty += 0.3 * k
            elif diff < 2.5 * threshold:
                penalty += 0.15 * k
            elif diff < 4 * threshold:
                penalty += 0.05 * k
            else:
                penalty -= 0.07 * k
        score += penalty
        if score < 0:
            score = 0
        if score > 2:
            for m in range(1, 6):
                val = capacity / m
                margin = 0.025 * val
                if abs(val - item) < margin:
                    score *= (1 + 0.04 * m)
        decay_factor = 0.9
        adjusted_score = 0
        for t in range(5):
            adjusted_score += score * (decay_factor ** t) / (t + 1)
        priorities[i] = adjusted_score
    return priorities
